import assert from 'assert';
import { ensureNoDisposablesAreLeakedInTestSuite } from '../../../../../base/test/common/utils.js';
import { getNamedRegions, NamedRange } from '../../browser/namedRangeProvider.js';
import { createTextModel } from '../../../../test/common/testTextModel.js';

suite('Named Region Provider', () => {
	ensureNoDisposablesAreLeakedInTestSuite();

	test('Detects simple named regions', () => {
		const lines = [
			'// #region MyRegion',
			'const x = 1;',
			'// #endregion'
		];
		const model = createTextModel(lines.join('\n'));
		const regions = getNamedRegions(model);

		assert.strictEqual(regions.length, 1);
		assert.strictEqual(regions[0].name, 'MyRegion');
		assert.strictEqual(regions[0].startLineNumber, 1);
		assert.strictEqual(regions[0].endLineNumber, 3);

		model.dispose();
	});

	test('Detects multiple named regions', () => {
		const lines = [
			'// #region First',
			'const a = 1;',
			'// #endregion',
			'',
			'// #region Second',
			'const b = 2;',
			'// #endregion'
		];
		const model = createTextModel(lines.join('\n'));
		const regions = getNamedRegions(model);

		assert.strictEqual(regions.length, 2);
		assert.strictEqual(regions[0].name, 'First');
		assert.strictEqual(regions[0].startLineNumber, 1);
		assert.strictEqual(regions[0].endLineNumber, 3);
		assert.strictEqual(regions[1].name, 'Second');
		assert.strictEqual(regions[1].startLineNumber, 5);
		assert.strictEqual(regions[1].endLineNumber, 7);

		model.dispose();
	});

	test('Extracts region name from comment', () => {
		const lines = [
			'// #region My Custom Region Name',
			'code here',
			'// #endregion'
		];
		const model = createTextModel(lines.join('\n'));
		const regions = getNamedRegions(model);

		assert.strictEqual(regions.length, 1);
		assert.strictEqual(regions[0].name, 'My Custom Region Name');

		model.dispose();
	});

	test('Handles regions with extra whitespace', () => {
		const lines = [
			'//   #region   SpacedName   ',
			'code',
			'//   #endregion'
		];
		const model = createTextModel(lines.join('\n'));
		const regions = getNamedRegions(model);

		assert.strictEqual(regions.length, 1);
		assert.strictEqual(regions[0].name, 'SpacedName');

		model.dispose();
	});

	test('Ignores unmatched endregion markers', () => {
		const lines = [
			'code',
			'// #endregion'
		];
		const model = createTextModel(lines.join('\n'));
		const regions = getNamedRegions(model);

		assert.strictEqual(regions.length, 0);

		model.dispose();
	});

	test('Returns empty array when no regions exist', () => {
		const lines = [
			'const x = 1;',
			'const y = 2;'
		];
		const model = createTextModel(lines.join('\n'));
		const regions = getNamedRegions(model);

		assert.strictEqual(regions.length, 0);

		model.dispose();
	});

	test('Handles nested regions (only counts matched pairs)', () => {
		const lines = [
			'// #region Outer',
			'// #region Inner',
			'code',
			'// #endregion',
			'// #endregion'
		];
		const model = createTextModel(lines.join('\n'));
		const regions = getNamedRegions(model);

		assert.strictEqual(regions.length, 2);
		assert.strictEqual(regions[0].name, 'Outer');
		assert.strictEqual(regions[0].startLineNumber, 1);
		assert.strictEqual(regions[0].endLineNumber, 5);
		assert.strictEqual(regions[1].name, 'Inner');
		assert.strictEqual(regions[1].startLineNumber, 2);
		assert.strictEqual(regions[1].endLineNumber, 4);

		model.dispose();
	});

	test('Handles different comment styles', () => {
		const lines = [
			'/* #region Block */',
			'const x = 1;',
			'/* #endregion */'
		];
		const model = createTextModel(lines.join('\n'));
		const regions = getNamedRegions(model);

		assert.strictEqual(regions.length, 1);
		assert.strictEqual(regions[0].name, 'Block');

		model.dispose();
	});

	test('Handles hash regions in block comments', () => {
		const lines = [
			'/*',
			' * #region Description',
			' */',
			'code',
			'/*',
			' * #endregion',
			' */'
		];
		const model = createTextModel(lines.join('\n'));
		const regions = getNamedRegions(model);

		assert.strictEqual(regions.length, 1);
		assert.strictEqual(regions[0].name, 'Description');

		model.dispose();
	});

	test('Returns regions in order', () => {
		const lines = [
			'// #region Alpha',
			'code1',
			'// #endregion',
			'// #region Beta',
			'code2',
			'// #endregion',
			'// #region Gamma',
			'code3',
			'// #endregion'
		];
		const model = createTextModel(lines.join('\n'));
		const regions = getNamedRegions(model);

		assert.strictEqual(regions.length, 3);
		assert.strictEqual(regions[0].name, 'Alpha');
		assert.strictEqual(regions[1].name, 'Beta');
		assert.strictEqual(regions[2].name, 'Gamma');

		model.dispose();
	});

	test('Preserves exact region names', () => {
		const lines = [
			'// #region camelCaseRegion',
			'code',
			'// #endregion'
		];
		const model = createTextModel(lines.join('\n'));
		const regions = getNamedRegions(model);

		assert.strictEqual(regions[0].name, 'camelCaseRegion');

		model.dispose();
	});

	test('NamedRange interface has correct properties', () => {
		const lines = [
			'// #region TestRegion',
			'const x = 1;',
			'// #endregion'
		];
		const model = createTextModel(lines.join('\n'));
		const regions = getNamedRegions(model);

		assert.strictEqual(regions.length, 1);
		const region = regions[0];

		// Verify all required properties exist
		assert('name' in region);
		assert('startLineNumber' in region);
		assert('endLineNumber' in region);

		// Verify types
		assert(typeof region.name === 'string');
		assert(typeof region.startLineNumber === 'number');
		assert(typeof region.endLineNumber === 'number');

		model.dispose();
	});
});

# Named Folding Regions - User Guide

## Quick Start

### Step 1: Mark Your Regions
Add region markers to your code using comments. The pattern is:
```
// #region RegionName
... your code ...
// #endregion
```

### Step 2: Open the Region Navigator
Press **`Ctrl+Shift+R`** on Windows/Linux or **`Cmd+Shift+R`** on macOS to open the "Go to Named Region" dialog.

### Step 3: Select a Region
Choose a region from the quick-pick list and press Enter to navigate to it.

---

## Examples

### Example 1: TypeScript Component

```typescript
// #region Imports
import React, { useState, useEffect } from 'react';
import { useSelector } from 'react-redux';
// #endregion

// #region Types
interface UserState {
  id: string;
  name: string;
  email: string;
}

type Props = {
  onSave: (user: UserState) => void;
};
// #endregion

// #region Component
export const UserForm: React.FC<Props> = ({ onSave }) => {
  const [formData, setFormData] = useState<UserState>({
    id: '',
    name: '',
    email: ''
  });

  // #region Event Handlers
  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    onSave(formData);
  };

  const handleChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const { name, value } = e.target;
    setFormData(prev => ({ ...prev, [name]: value }));
  };
  // #endregion

  return (
    <form onSubmit={handleSubmit}>
      {/* form fields */}
    </form>
  );
};
// #endregion
```

When you press `Ctrl+Shift+R`, you'll see:
```
Imports                      Line 1
Types                        Line 5
Component                    Line 15
Event Handlers               Line 27
```

---

### Example 2: Python File

```python
# #region Configuration
DEBUG = True
DATABASE_URL = "postgresql://localhost/mydb"
SECRET_KEY = "your-secret-key"
# #endregion

# #region Database Models
class User(Base):
    __tablename__ = "users"

    id = Column(Integer, primary_key=True)
    username = Column(String, unique=True)
    email = Column(String, unique=True)
# #endregion

# #region API Routes
@app.post("/users/")
async def create_user(user: UserSchema):
    db_user = User(**user.dict())
    db.add(db_user)
    db.commit()
    return db_user
# #endregion
```

Quick-pick shows:
```
Configuration                Line 1
Database Models              Line 6
API Routes                   Line 16
```

---

### Example 3: JavaScript with Multiple Nested Regions

```javascript
// #region Utilities

  // #region String Helpers
  const toUpperCase = (str) => str.toUpperCase();
  const toLowerCase = (str) => str.toLowerCase();
  const trim = (str) => str.trim();
  // #endregion

  // #region Array Helpers
  const flatten = (arr) => arr.reduce((acc, val) =>
    acc.concat(Array.isArray(val) ? flatten(val) : val), []
  );
  const unique = (arr) => [...new Set(arr)];
  // #endregion

// #endregion

// #region Business Logic
function processUserData(users) {
  return users
    .map(u => ({ ...u, name: toUpperCase(u.name) }))
    .filter(u => u.active);
}
// #endregion
```

Quick-pick shows:
```
Utilities                    Line 1
String Helpers               Line 3
Array Helpers                Line 9
Business Logic               Line 17
```

Note: Nested regions (String Helpers, Array Helpers inside Utilities) are all listed independently.

---

## Advanced Usage

### Navigating with Description Hints
The quick-pick shows both the region name and its line number:
```
MyRegion                     Line 42
AnotherRegion                Line 87
```

You can use this to quickly jump to specific sections of your file.

### Filtering by Name
Once the dialog is open, you can type to filter regions:
- Press `Ctrl+Shift+R` to open
- Type "imports" to filter to regions with "imports" in the name
- Press Enter to navigate

### Keyboard Navigation
- **Up/Down Arrows**: Navigate between regions
- **Ctrl+P** or **Cmd+P**: Filter by typing
- **Enter**: Jump to selected region
- **Esc**: Cancel

---

## Best Practices

### 1. Meaningful Names
Use clear, descriptive names:
```typescript
// GOOD
// #region API Request Handlers

// LESS CLEAR
// #region stuff
```

### 2. Logical Organization
Group related code:
```typescript
// #region Imports
// #region Types
// #region Components
// #region Utilities
```

### 3. Keep Region Sizes Reasonable
Use regions to organize by feature, not by individual functions:
```typescript
// GOOD - Logical grouping
// #region User Management
function getUser() { }
function createUser() { }
function deleteUser() { }
// #endregion

// LESS CLEAR - Too granular
// #region Get User
function getUser() { }
// #endregion
```

### 4. Comment Style Consistency
Use consistent comment styles within your file:
```typescript
// Good - consistent style
// #region Section 1
// #endregion

// #region Section 2
// #endregion
```

---

## Supported Comment Styles

All of these work:

```typescript
// #region RegionName
// #endregion

/* #region RegionName */
/* #endregion */

/*
 * #region RegionName
 */
code here
/*
 * #endregion
 */

# #region RegionName (Python)
# #endregion
```

---

## Tips & Tricks

### Tip 1: Quick Navigation in Large Files
Instead of scrolling, use `Ctrl+Shift+R` to jump directly to any section:

1. Press `Ctrl+Shift+R`
2. Type the region name
3. Press Enter

Much faster than scrolling!

### Tip 2: Organizing by Visibility
Use regions to mark public vs private sections:
```typescript
// #region Public API
export function publicFunction() { }
// #endregion

// #region Internal Helpers
function internalHelper() { }
// #endregion
```

### Tip 3: Cross-File Navigation
Add regions with consistent naming across files:
```typescript
// src/api.ts
// #region User Endpoints

// src/hooks.ts
// #region User Hooks

// src/types.ts
// #region User Types
```

This makes it easy to find related code across your project!

### Tip 4: README Integration
Document your code structure in a README:
```markdown
## Project Structure

- **Imports** - External dependencies
- **Types** - TypeScript interfaces
- **Components** - React components
- **Utilities** - Helper functions
- **Hooks** - Custom React hooks
```

---

## Troubleshooting

### "No named regions found in this file"
This means there are no `#region` / `#endregion` markers in the file. Add some and try again!

### Dialog doesn't appear or shortcut doesn't work
Check:
1. Is Folding enabled? (Check Editor settings)
2. Are you in a text editor? (Not in settings, sidebar, etc.)
3. Try remapping the keybinding if needed

### Region isn't showing up in the list
Make sure:
1. You have a matching `#endregion` marker
2. The `#region` marker is followed by a name: `#region Name`
3. The region markers are in comments (not in strings)

---

## Comparison with VS Code's Built-in Folding

| Feature | Built-in Folding | Named Regions |
|---------|------------------|---------------|
| Auto-detect syntax | ✅ | ❌ |
| Manual markers | ✅ | ✅ |
| Named regions | ❌ | ✅ |
| Quick navigation | ❌ | ✅ |
| Custom structure | ❌ | ✅ |

Use **Named Regions** when you want custom control over your code sections!

---

## Integration with Other Features

### Works with VS Code Folding Controls
Your regions will appear in VS Code's folding gutter alongside syntax-based folds.

### Outline View Compatible
Regions are separate from the outline view - use both together!

### Works with Multiple Languages
Use regions in any language that supports comments:
- JavaScript/TypeScript
- Python
- Java
- C#
- C/C++
- Go
- Rust
- And many more!

---

## Related Commands

- **Fold/Unfold Regions** - `Ctrl+K Ctrl+8` / `Ctrl+K Ctrl+9`
- **Fold All Comments** - `Ctrl+K Ctrl+/`
- **Create Manual Fold** - `Ctrl+K Ctrl+,`
- **Go to Named Region** - `Ctrl+Shift+R` ← New!

---

## More Information

For implementation details and architecture, see:
- `IMPLEMENTATION_SUMMARY.md` - Technical details
- Source files:
  - `src/vs/editor/contrib/folding/browser/namedRangeProvider.ts`
  - `src/vs/editor/contrib/folding/browser/folding.ts`
  - `src/vs/editor/contrib/folding/test/browser/namedRangeProvider.test.ts`

