# Named Folding Regions - User Guide

## Quick Start

### Step 1: Mark Your Regions
Add region markers to your code using comments. The pattern is:
```
// #region RegionName
... your code ...
// #endregion
```

### Step 2: Open the Region Navigator
Press **`Ctrl+Shift+R`** on Windows/Linux or **`Cmd+Shift+R`** on macOS to open the "Go to Named Region" dialog.

### Step 3: Select a Region
Choose a region from the quick-pick list and press Enter to navigate to it.

---

## Examples

### Example 1: TypeScript Component

```typescript
// #region Imports
import React, { useState, useEffect } from 'react';
import { useSelector } from 'react-redux';
// #endregion

// #region Types
interface UserState {
  id: string;
  name: string;
  email: string;
}

type Props = {
  onSave: (user: UserState) => void;
};
// #endregion

// #region Component
export const UserForm: React.FC<Props> = ({ onSave }) => {
  const [formData, setFormData] = useState<UserState>({
    id: '',
    name: '',
    email: ''
  });

  // #region Event Handlers
  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    onSave(formData);
  };

  const handleChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const { name, value } = e.target;
    setFormData(prev => ({ ...prev, [name]: value }));
  };
  // #endregion

  return (
    <form onSubmit={handleSubmit}>
      {/* form fields */}
    </form>
  );
};
// #endregion
```

When you press `Ctrl+Shift+R`, you'll see:
```
Imports                      Line 1
Types                        Line 5
Component                    Line 15
Event Handlers               Line 27
```

